SELECT COUNT(*)
FROM login_logs
WHERE user_id = #{userId}
  AND ip_address = #{ip}
  AND login_result = 'SUCCESS'
  AND created_at > #{since}

SELECT COUNT(*)
FROM login_logs
WHERE user_id = #{userId}
  AND device_fingerprint = #{fingerprint}
  AND login_result = 'SUCCESS'
  AND created_at > #{since}

SELECT 
FROM login_logs
WHERE (is_geo_abnormal = true OR is_device_abnormal = true)

    AND user_id = #{userId}


    AND created_at >= #{startTime}


    AND created_at <= #{endTime}

ORDER BY created_at DESC

SELECT 
FROM login_logs
WHERE login_result = 'FAILURE'

    AND user_id = #{userId}


    AND created_at >= #{startTime}


    AND created_at <= #{endTime}

ORDER BY created_at DESC

SELECT 
FROM login_logs


        AND user_id = #{userId}


        AND login_type = #{loginType}


        AND login_result = #{loginResult}


        AND is_geo_abnormal = #{isGeoAbnormal}


        AND is_device_abnormal = #{isDeviceAbnormal}


        AND ip_address LIKE CONCAT('%', #{ipAddress}, '%')


        AND created_at >= #{startTime}


        AND created_at <= #{endTime}


ORDER BY created_at DESC

mapper.update:
UPDATE login_logs
SET is_geo_abnormal = #{isGeoAbnormal},
    is_device_abnormal = #{isDeviceAbnormal}
WHERE id = #{id}
